+#[test]
+fn terminal_app_review_done_prompt_highlights_closes_and_reopens_patch_agent_chat() {
+    let root = git_repo("terminal-app-review-done-confirmation");
+    fs::write(root.join("README.md"), "before\n").unwrap();
+    Command::new("git")
+        .current_dir(&root)
+        .args(["add", "README.md"])
+        .status()
+        .unwrap();
+    Command::new("git")
+        .current_dir(&root)
+        .args(["commit", "-m", "ADD initial readme fixture"])
+        .status()
+        .unwrap();
+    let backend = FakeBackend::new([
+        "implemented patch\n@work-leaf patch update readme\n--- a/README.md\n+++ b/README.md\n@@ -1 +1 @@\n-before\n+after\n@work-leaf end\n@work-leaf done",
+        "summary: README changes from before to after",
+        "NO_FINDINGS",
+        "reopened reply",
+    ]);
+    let chat = CommandChat::new(root, backend);
+    let mut app = TerminalApp::new(chat, 100, 24);
+
+    app.handle_bytes(b":new update readme\n");
+    assert!(app.wait_for_idle(Duration::from_secs(2)));
+
+    let reviewed_frame = app.render_frame();
+    assert!(reviewed_frame.starts_with('\u{7}'));
+    assert!(reviewed_frame.contains("\u{1b}[7m"));
+    assert!(reviewed_frame.contains("work-leaf: review complete. Is this feature done? yes/no"));
+
+    app.handle_bytes(b"yes\n");
+
+    assert!(!app.ui().render_left_pane().contains(" user-1  working"));
+    assert!(
+        app.render_frame()
+            .contains("work-leaf: feature marked done")
+    );
+
+    app.handle_bytes(b"please reopen the feature\n");
+    assert!(app.wait_for_idle(Duration::from_secs(1)));
+
+    let reopened_left_pane = app.ui().render_left_pane();
+    assert!(reopened_left_pane.contains(" user-1  working"));
+    let reopened_frame = app.render_frame();
+    assert!(reopened_frame.contains("work-leaf: feature reopened"));
+    assert!(reopened_frame.contains("user: please reopen the feature"));
+    assert!(reopened_frame.contains("reopened reply"));
+}
